def verify_requirements_file_integrity(
    requirements_path: str,
    checksum_path: Optional[str] = None
) -> bool:
    """
    Verify the integrity of requirements.txt using a known-good checksum.
    
    This prevents tampering with the requirements file in the repository
    or during transit.
    """
    req_file = Path(requirements_path)
    if not req_file.exists():
        logger.error(f"Requirements file not found: {requirements_path}")
        return False

    if checksum_path:
        checksum_file = Path(checksum_path)
        if checksum_file.exists():
            with open(req_file, "rb") as f:
                file_hash = hashlib.sha256(f.read()).hexdigest()
            with open(checksum_file, "r") as f:
                checksums = json.load(f)
            expected_hash = checksums.get(str(req_file.name))
            if expected_hash and file_hash != expected_hash:
                logger.error(
                    f"Checksum mismatch for {requirements_path}! "
                    f"Expected: {expected_hash}, Got: {file_hash}. "
                    f"Possible tampering detected."
                )
                return False
            elif expected_hash:
                logger.info(f"Checksum verified for {requirements_path}")
            else:
                logger.warning(
                    f"No checksum entry found for {req_file.name} in {checksum_path}"
                )
        else:
            logger.warning(
                f"Checksum file not found: {checksum_path}. "
                f"Skipping integrity check."
            )

    return True


def generate_requirements_checksum(requirements_path: str, checksum_path: str) -> None:
    """
    Generate a SHA-256 checksum file for requirements.txt.
    
    Run this once to create the checksum file, then commit it to version control.
    Usage: python install_deps.py --generate-checksum
    """
    req_file = Path(requirements_path)
    if not req_file.exists():
        logger.error(f"Requirements file not found: {requirements_path}")
        return

    with open(req_file, "rb") as f:
        file_hash = hashlib.sha256(f.read()).hexdigest()

    checksum_file = Path(checksum_path)
    checksums = {}
    if checksum_file.exists():
        with open(checksum_file, "r") as f:
            checksums = json.load(f)

    checksums[req_file.name] = file_hash

    with open(checksum_file, "w") as f:
        json.dump(checksums, f, indent=2)

    logger.info(f"Generated checksum for {requirements_path}: {file_hash}")
    logger.info(f"Checksum saved to {checksum_path}")


def validate_requirements_content(requirements_path: str) -> bool:
    """
    Validate requirements.txt content for suspicious patterns that could
    indicate supply chain attacks.
    """
    suspicious_patterns = [
        "--index-url",
        "--extra-index-url",
        "--find-links",
        "--trusted-host",
        "git+http://",   # Insecure git URLs (https is ok but should be reviewed)
        "svn+",
        "bzr+",
        "hg+",
    ]

    req_file = Path(requirements_path)
    with open(req_file, "r") as f:
        lines = f.readlines()

    issues_found = False
    for line_num, line in enumerate(lines, 1):
        stripped = line.strip()
        if not stripped or stripped.startswith("#"):
            continue

        for pattern in suspicious_patterns:
            if pattern in stripped.lower():
                logger.error(
                    f"Suspicious pattern '{pattern}' found in "
                    f"{requirements_path}:{line_num}: {stripped}"
                )
                issues_found = True

        # Warn about URL-based installs (potential for hijacking)
        if stripped.startswith("http://"):
            logger.error(
                f"Insecure HTTP URL found in "
                f"{requirements_path}:{line_num}: {stripped}"
            )
            issues_found = True

        # Warn about packages without version pinning in CI/CD
        if (
            not stripped.startswith("-")
            and not stripped.startswith("#")
            and "==" not in stripped
            and ">=" not in stripped
            and "<=" not in stripped
            and "~=" not in stripped
            and "!=" not in stripped
            and "@" not in stripped
            and not stripped.startswith("git+")
            and not stripped.startswith("https://")
        ):
            logger.warning(
                f"Package without version pin in "
                f"{requirements_path}:{line_num}: {stripped}. "
                f"Consider pinning versions for reproducible builds."
            )

    return not issues_found


